import{_ as t,c as o,o as i,ag as n}from"./chunks/framework.S-Qvb3wi.js";const g=JSON.parse('{"title":"What We Do","description":"","frontmatter":{},"headers":[],"relativePath":"What-we-do.md","filePath":"What-we-do.md"}'),a={name:"What-we-do.md"};function r(s,e,l,c,d,u){return i(),o("div",null,e[0]||(e[0]=[n('<h1 id="what-we-do" tabindex="-1">What We Do <a class="header-anchor" href="#what-we-do" aria-label="Permalink to &quot;What We Do&quot;">​</a></h1><p>With the core mission of <strong>&quot;building a trusted, efficient AI network connecting supply and demand&quot;</strong>, DGrid addresses the industry pain points of market fragmentation and centralized control. We break down the fragmentation and value mismatch in the AI ecosystem, providing a one-stop solution for both Web3 and traditional AI sectors. Adhering to the core principle that <strong>&quot;AI should serve the open web&quot;</strong>, we are committed to enabling high-quality AI capabilities (including LLMs and AI Agents) to achieve efficient flow, fair distribution, and trusted verification through technological innovation and ecosystem collaboration.</p><p>To tackle the core challenges—such as the explosion of model supply alongside fragmented interfaces, high integration costs for developers, value monopolization of creators, and non-auditable inference results—DGrid has built a three-tier architecture: <strong>&quot;Decentralized Routing &amp; Verification Network + LLM &amp; Agent Free Market + AI DAO&quot;</strong>, which connects the entire chain from AI capability supply to demand matching:</p><ul><li>Through a unified API and intelligent routing, we resolve interface fragmentation. Developers can access thousands of models and Agents without redundant development, significantly lowering integration barriers.</li><li>We build a trusted inference environment using the <strong>Proof of Quality (PoQ)</strong> algorithm, enabling verifiability and traceability of AI execution processes and output results, and bridging the trust gap in Web3 AI.</li><li>We establish an open LLM &amp; Agent free market, allowing creators such as model providers and prompt engineers to set their own prices and profit directly from global users, breaking platform monopolies.</li><li>Via a distributed node network and elastic scheduling mechanism, we address the high costs, single points of failure, and censorship risks of centralized AI, while providing a merit-based incentive system for node operators.</li></ul><p>Ultimately, DGrid aims to become the <strong>&quot;value hub&quot;</strong> of the AI and Web3 ecosystems. We not only deliver cost-effective, verifiable, high-quality AI services to users but also build a fair and win-win collaboration platform for ecosystem participants, advancing AI from <strong>&quot;centralized services&quot;</strong> to a <strong>&quot;foundational public utility of the open web&quot;</strong>.</p><h2 id="core-values" tabindex="-1">Core Values <a class="header-anchor" href="#core-values" aria-label="Permalink to &quot;Core Values&quot;">​</a></h2><ul><li><strong>Decentralization</strong>: AI belongs to the open web, not centralized platforms, ensuring equal participation of all ecosystem stakeholders.</li><li><strong>Accessibility</strong>: Anyone can join as a node operator, developer, creator, or user, with low barriers to entry.</li><li><strong>Trustlessness</strong>: Based on on-chain permission and auditing mechanisms, services are verifiable and traceable without relying on third-party trust.</li><li><strong>Scalability</strong>: Modular design enables flexible model deployment, inference, and caching, adapting to diverse scenario requirements.</li><li><strong>Value Discoverability</strong>: Intelligent routing makes inference resources &quot;routable, verifiable, and comparable in price&quot;, enabling efficient allocation of intelligent liquidity.</li></ul>',7)]))}const p=t(a,[["render",r]]);export{g as __pageData,p as default};
